print("=== Length Validation ===")
all_ok = True
for domain_name in ALL:
    for key, value in ALL[domain_name].items():
        L = len(value)
        status = "OK" if L >= 1000 else "FAIL"
        if L < 1000:
            all_ok = False
        print(f"  {domain_name}.{key}: len={L} {status}")

if not all_ok:
    print("\n*** VALIDATION FAILED ***")
    exit(1)

total_entries = sum(len(ALL[d]) for d in ALL)
