# WRITE supplement-group3.js
# ======================================================================
print("\n=== Writing supplement-group3.js ===")
with open('supplement-group3.js', 'w', encoding='utf-8') as f:
    f.write('// 易道智鉴 · 知识库补充内容 第3组\n')
    f.write('// 生成时间：2026.06.28\n')
    f.write('// 扩展50-999 -> 1000+ 涵盖6个领域\n\n')
    f.write('const SUPPLEMENT_GROUP3 = {\n')
    
    for domain_name in ['fengshui', 'tizhi', 'shishen', 'nayin', 'shensha', 'hechong']:
        entries = ALL.get(domain_name, {})
        f.write(f'  {domain_name}: {{\n')
        for key, value in entries.items():
            escaped = value.replace('\\', '\\\\').replace('\n', '\\n').replace('"', '\\"')
            f.write(f'    "{key}": "{escaped}",\n')
        f.write('  },\n')
    
    f.write('};\n\n')
    f.write('if (typeof module !== "undefined" && module.exports) {\n')
    f.write('  module.exports = SUPPLEMENT_GROUP3;\n')
    f.write('}\n')

print("supplement-group3.js written OK")

# ======================================================================
# MERGE into authoritative-knowledge-base.js
# ======================================================================
print("\n=== Merging into authoritative-knowledge-base.js ===")

with open('authoritative-knowledge-base.js', 'r', encoding='utf-8') as f:
    original = f.read()

modified = original
total_replaced = 0
replaced_entries = []

for domain_name in ['fengshui', 'tizhi', 'shishen', 'nayin', 'shensha', 'hechong']:
    entries = ALL.get(domain_name, {})
    
    domain_start = modified.find(f'\n  {domain_name}:')
    if domain_start < 0:
        domain_start = modified.find(f'  {domain_name}:')
        if domain_start < 0:
            print(f'  WARNING: domain {domain_name} not found')
            continue
    
    for key, new_value in entries.items():
        key_search = f'"{key}":'
        search_start = domain_start
        
        while True:
            pos = modified.find(key_search, search_start)
            if pos < 0:
                break
            
            qstart = modified.find('"', pos + len(key_search))
            if qstart < 0:
                break
            qstart += 1
            
            qend = qstart
            while qend < len(modified):
                c = modified[qend]
                if c == '\\':
                    qend += 2
                    continue
                if c == '"':
                    break
                qend += 1
            
            old_value = modified[qstart:qend]
            
            if 50 <= len(old_value) < 1000:
                escaped_new = new_value.replace('\\', '\\\\').replace('\n', '\\n').replace('"', '\\"')
                modified = modified[:qstart] + escaped_new + modified[qend:]
                total_replaced += 1
                replaced_entries.append(f'  {domain_name}.{key} ({len(old_value)} -> {len(new_value)} chars)')
                print(f'  REPLACED: {domain_name}.{key} ({len(old_value)} -> {len(new_value)} chars)')
                break
            else:
                search_start = qend + 1

print(f'\n=== TOTAL REPLACED: {total_replaced} entries ===')
if total_replaced > 0:
    print('Modified entries:')
    for e in replaced_entries:
        print(e)

with open('authoritative-knowledge-base.js', 'w', encoding='utf-8') as f:
    f.write(modified)

print("\nDONE! authoritative-knowledge-base.js updated successfully.")
